// --- 3. HELPER FUNCTIONS ---

const getRandom = (arr: string[]) => arr[Math.floor(Math.random() * arr.length)];

// To prevent repetition
const GLOBAL_HISTORY = new Set<string>();

const getContentNoRepeat = (type: 'jokes' | 'facts' | 'stories' | 'security_tips') => {
  const source = DB[type];
  const available = source.filter(item => !GLOBAL_HISTORY.has(item));

  if (available.length === 0) {
    // Reset if we used everything
    source.forEach(item => GLOBAL_HISTORY.delete(item));
    return getRandom(source); // Start over
  }

  const selected = getRandom(available);
  GLOBAL_HISTORY.add(selected);
  return selected;
};

// --- 4. THE BRAIN (PROCESSING LOGIC) ---

const processOfflineInput = (text: string, vaultStats?: {count: number, weak: number}): string => {
  // Normalize text before processing
  const cleanText = normalizeArabic(text.toLowerCase());
  let response = "";

  // 1. Check for Password Generation Request (Explicit)
  if (cleanText.match(/كلمه سر|باسورد|رمز|password/)) {
     const pass = Array.from(crypto.getRandomValues(new Uint32Array(16)))
        .map(x => "ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnpqrstuvwxyz23456789!@#$%&"[x % 64])
        .join('');
     return `سم، هذي كلمة سر قوية جداً من أجلك: 👇\n\n[[PASSWORD:${pass}]]`;
  }

  // 2. Contextual "More" (Did user say "another one"?)
  if (cleanText.match(/كمان|بعد|غيرها|ثانيه|زياده/) && MEMORY.lastTopic) {
      switch (MEMORY.lastTopic) {
          case 'joke': return getRandom(DB.patterns.find(p => p.intent === 'more')?.responses || []) + "\n\n" + getContentNoRepeat('jokes');
          case 'fact': return getRandom(DB.patterns.find(p => p.intent === 'more')?.responses || []) + "\n\n" + getContentNoRepeat('facts');
          case 'story': return getRandom(DB.patterns.find(p => p.intent === 'more')?.responses || []) + "\n\n" + getContentNoRepeat('stories');
          case 'security': return getRandom(DB.patterns.find(p => p.intent === 'more')?.responses || []) + "\n\n" + getContentNoRepeat('security_tips');
      }
  }

  // 3. Pattern Matching Engine
  let matchedPattern = null;
  for (const p of DB.patterns) {
      if (p.regex.test(cleanText)) {
          matchedPattern = p;
          break;
      }
  }

  // 4. Action based on Match
  if (matchedPattern) {
      const prefix = getRandom(matchedPattern.responses);

      switch (matchedPattern.intent) {
          case 'joke':
              MEMORY.lastTopic = 'joke';
              response = `${prefix}\n\n${getContentNoRepeat('jokes')}`;
              break;
          case 'story':
              MEMORY.lastTopic = 'story';
              response = `${prefix}\n\n${getContentNoRepeat('stories')}`;
              break;
          case 'fact':
              MEMORY.lastTopic = 'fact';
              response = `${prefix}\n\n${getContentNoRepeat('facts')}`;
              break;
          case 'security':
              MEMORY.lastTopic = 'security';
              response = `${prefix}\n\n${getContentNoRepeat('security_tips')}`;
              break;
          case 'install':
              response = prefix; // The response itself is the instruction
              break;
          case 'greeting':
              const hour = new Date().getHours();
              const timeGreeting = hour < 12 ? "صباح الخير" : "مساء النور";
              response = `${prefix} ${timeGreeting} ${MEMORY.userNickname}!`;
              break;
          default:
              MEMORY.lastTopic = 'general';
              response = prefix;
      }
  } else {
      // 5. Fallback Intelligence
      MEMORY.lastTopic = 'general';

      // Removed strict length check, now relies on pattern matching primarily.
      if (cleanText.length < 2) { // Only block single chars
          response = "كمل، أنا أسمعك..";
      } else if (cleanText.includes("؟")) {
          response = "سؤال جميل.. بس بصراحة وأنا في الوضع المحلي (Offline) معلوماتي محدودة، بس في السوالف والأمان أنا موجود!";
      } else if (cleanText.includes("وين")) {
          response = "موجود بجوالك، أقرب لك من أنفاسك.";
      } else {
          const reflections = [
              "حلو.. وش كمان؟",
              "تصدق نقطة مثيرة للاهتمام.",
              `فعلاً يا ${MEMORY.userNickname}، كلامك صحيح.`,
              "أنا أتفق معك.",
              "ياخي تعجبني سواليفك."
          ];
          response = getRandom(reflections);
      }
  }

  return response;
};

// --- PUBLIC API ---

export const generateSecurityAdvice = async (message: string, vaultStats?: {count: number, weak: number}): Promise<string> => {
  // Always use offline brain if explicitly offline
  if (!navigator.onLine) {
    return processOfflineInput(message, vaultStats);
  }

  try {
    const ai = getClient();
    if (!ai) return processOfflineInput(message, vaultStats);

    const model = "gemini-2.5-flash"; 

    // Updated System Instruction to know about PWA status
    const systemInstruction = `أنت تطبيق ويب تقدمي (PWA) واسمك "حارسي الأمين".
    - وظيفتك: حماية كلمات المرور والدردشة الممتعة.
    - اللهجة: سعودية بيضاء ودودة جداً.

    **تعليمات مهمة جداً:**
    - إذا سألك المستخدم عن "التحميل" أو "التثبيت" أو "كيف احملك" أو "وين التطبيق":
      1. اشرح له أنك تطبيق ويب يعمل بدون متجر.
      2. لمستخدمي الآيفون: قل "اضغط زر المشاركة (سهم طالع من مربع) بالأسفل، ثم اختر 'إضافة إلى الصفحة الرئيسية' (Add to Home Screen)."
      3. لمستخدمي الأندرويد: قل "اضغط على القائمة (3 نقاط) ثم اختر 'تثبيت التطبيق' (Install App)."

    - إذا طلب نكتة أو قصة، كن مبدعاً ولا تكرر.
    - إذا طلب كلمة سر، استخدم الصيغة: [[PASSWORD:xxx]]
    `;

    const response = await ai.models.generateContent({
      model: model,
      contents: message,
      config: { systemInstruction: systemInstruction }
    });

    return response.text || processOfflineInput(message, vaultStats);
  } catch (error) {
    console.log("Network AI failed, switching to local brain");
    return processOfflineInput(message, vaultStats);
  }
};

