  const getRandomColor = () => {
    const colors = ['from-blue-600 to-blue-800', 'from-purple-600 to-purple-800', 'from-emerald-600 to-emerald-800', 'from-rose-600 to-rose-800', 'from-orange-600 to-orange-800', 'from-slate-700 to-slate-900'];
    return colors[Math.floor(Math.random() * colors.length)];
