                         style={{ pointerEvents: 'auto' }} // Ensure it catches clicks
                    >
                        <Trash2 className="w-4 h-4" />
                    </button>

                    <div className="flex justify-between items-start mb-8 pl-12"> {/* Padding to avoid overlap */}
                        <div className="flex items-center gap-2">
