                    <button onClick={() => setSortOption('newest')} className={`w-full text-right px-4 py-3 text-sm hover:bg-zinc-800 ${sortOption === 'newest' ? 'text-primary' : 'text-white'}`}>الأحدث إضافة</button>
                    <button onClick={() => setSortOption('oldest')} className={`w-full text-right px-4 py-3 text-sm hover:bg-zinc-800 ${sortOption === 'oldest' ? 'text-primary' : 'text-white'}`}>الأقدم إضافة</button>
                    <button onClick={() => setSortOption('az')} className={`w-full text-right px-4 py-3 text-sm hover:bg-zinc-800 ${sortOption === 'az' ? 'text-primary' : 'text-white'}`}>الاسم (أ-ي)</button>
                    <button onClick={() => setSortOption('za')} className={`w-full text-right px-4 py-3 text-sm hover:bg-zinc-800 ${sortOption === 'za' ? 'text-primary' : 'text-white'}`}>الاسم (ي-أ)</button>
                </div>
            )}
        </div>
      </div>

      <div className="flex gap-2 mb-8 overflow-x-auto no-scrollbar pb-1">
        {categories.map((cat) => (
            <button key={cat.id} onClick={() => setSelectedCategory(cat.id)} className={`px-5 py-2.5 rounded-full text-sm font-bold whitespace-nowrap transition-all duration-300 ${selectedCategory === cat.id ? 'bg-white text-black shadow-lg scale-105' : 'bg-zinc-800/50 text-zinc-400 border border-zinc-700/30 hover:bg-zinc-700'}`}>
                {cat.label}
            </button>
        ))}
      </div>

      <div className="space-y-4">
        {displayedAccounts.length === 0 ? (
            <div className="text-center py-16 opacity-50 flex flex-col items-center animate-fade-in-up">
                <div className="w-20 h-20 bg-zinc-900 rounded-full flex items-center justify-center mb-4 border border-zinc-800">
                   <Lock className="w-10 h-10 text-zinc-700" />
                </div>
                <h3 className="text-lg font-bold text-zinc-300">لا توجد حسابات</h3>
