const CACHE_NAME = 'my-guardian-v4-relative';

// Core assets to cache immediately on install
// CRITICAL: Use relative paths (./) to support sub-directory deployments
const PRECACHE_URLS = [
  './',
  './index.html',
  './manifest.json',
  './index.tsx', // Entry point
  'https://cdn.tailwindcss.com', // Styles
  'https://fonts.googleapis.com/css2?family=Tajawal:wght@300;400;500;700;800&display=swap' // Fonts
];

// Install Event: Cache core files
self.addEventListener('install', (event) => {
  self.skipWaiting(); // Force activation
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => {
      console.log('[Service Worker] Precaching core assets');
      return cache.addAll(PRECACHE_URLS);
    })
  );
});

// Activate Event: Clean up old caches
self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches.keys().then((cacheNames) => {
      return Promise.all(
        cacheNames.map((cacheName) => {
          if (cacheName !== CACHE_NAME) {
            console.log('[Service Worker] Deleting old cache:', cacheName);
            return caches.delete(cacheName);
          }
        })
      );
    }).then(() => self.clients.claim()) // Take control of all clients immediately
  );
});

// Fetch Event: Network First for HTML/App code, Cache First for specific assets
self.addEventListener('fetch', (event) => {
  // Only handle GET requests
  if (event.request.method !== 'GET') return;

  // Skip cross-origin requests that aren't in our precache (like random images) to avoid CORS issues
  if (!event.request.url.startsWith(self.location.origin) && !PRECACHE_URLS.includes(event.request.url)) {
     return;
  }

  event.respondWith(
    (async () => {
      const cache = await caches.open(CACHE_NAME);

      // 1. Try to get from cache first (Fastest UI)
      const cachedResponse = await cache.match(event.request);
      if (cachedResponse) {
          // Return cached response, but update it in background (Stale-While-Revalidate)
          // except for index.html which we want fresh if possible, or fallback to cache
          fetch(event.request).then(networkResponse => {
              if (networkResponse && networkResponse.status === 200) {
                  cache.put(event.request, networkResponse.clone());
              }
          }).catch(() => {});
          return cachedResponse;
      }

      // 2. Fetch from network
      try {
          const networkResponse = await fetch(event.request);
          if (networkResponse && networkResponse.status === 200 && (networkResponse.type === 'basic' || networkResponse.type === 'cors')) {
            cache.put(event.request, networkResponse.clone());
          }
          return networkResponse;
      } catch (error) {
          // Network failed
          console.log('[Service Worker] Network failed for:', event.request.url);
          // Fallback logic could go here
      }
    })()
  );
});

