  './index.tsx',
  'https://cdn.tailwindcss.com',
  'https://fonts.googleapis.com/css2?family=Tajawal:wght@300;400;500;700;800&display=swap'
];

self.addEventListener('install', (event) => {
  self.skipWaiting();
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => {
      // We specifically cache the APP_SHELL separately to ensure it exists
      cache.add(new Request(APP_SHELL, { cache: 'reload' }));
      return cache.addAll(ASSETS.map(url => new Request(url, { cache: 'reload' }))).catch(e => console.log(e));
    })
  );
});

self.addEventListener('activate', (event) => {
  event.waitUntil(
    Promise.all([
      self.clients.claim(), // Take control immediately
      caches.keys().then((keys) => {
        return Promise.all(
          keys.map((key) => {
            if (key !== CACHE_NAME) {
              console.log('Clearing old cache...', key);
              return caches.delete(key);
            }
          })
        );
      })
    ])
  );
});

self.addEventListener('fetch', (event) => {
  // STRATEGY: App Shell Model
  // If it's a navigation request (opening the app), ignore the URL and give index.html
  if (event.request.mode === 'navigate') {
    event.respondWith(
      caches.match(APP_SHELL).then((response) => {
        // Return cached index.html if found
        if (response) return response;

        // If not found in cache, try network
        return fetch(event.request).catch(() => {
           // If network fails and cache fails, return a basic fallback
           return new Response('<h1>جاري إعادة التحميل...</h1><script>location.reload()</script>', {
             headers: {'Content-Type': 'text/html'}
           });
        });
      })
    );
    return;
  }

  // For everything else (images, scripts), try cache first, then network
  event.respondWith(
    caches.match(event.request).then((response) => {
      return response || fetch(event.request);
    })
  );
});

const CACHE_NAME = 'my-guardian-v11-network-first';
const APP_SHELL = './index.html';

const ASSETS = [
  './',
  './index.html',
  './manifest.json',
  './index.tsx',
  'https://cdn.tailwindcss.com',
  'https://fonts.googleapis.com/css2?family=Tajawal:wght@300;400;500;700;800&display=swap'
];

self.addEventListener('install', (event) => {
  self.skipWaiting();
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => {
      // Cache critical assets
      return cache.addAll(ASSETS.map(url => new Request(url, { cache: 'reload' }))).catch(e => console.log(e));
    })
  );
});

self.addEventListener('activate', (event) => {
  event.waitUntil(
    Promise.all([
      self.clients.claim(),
      caches.keys().then((keys) => {
        return Promise.all(
          keys.map((key) => {
            if (key !== CACHE_NAME) {
              return caches.delete(key);
            }
          })
        );
      })
    ])
  );
});

self.addEventListener('fetch', (event) => {
  // STRATEGY: NETWORK FIRST (The "Unstuck" Strategy)
  // 1. Try to get the fresh page from the internet.
  // 2. If internet works, update the cache with the new page.
  // 3. If internet fails, return the cached page.

  if (event.request.mode === 'navigate') {
    event.respondWith(
      fetch(event.request)
        .then((networkResponse) => {
            return networkResponse;
        })
        .catch(() => {
            // Network failed, try to serve the offline page
            return caches.match(APP_SHELL).then(response => {
                if (response) return response;
                // Try to find index.html in other ways
                return caches.match('./index.html')
                    .then(r => r || caches.match('index.html'))
                    .then(r => r || new Response('<h1 style="color:white;text-align:center;margin-top:50px">أنت غير متصل (Offline)</h1>', {headers: {'Content-Type': 'text/html'}}));
            });
        })
    );
    return;
  }

  // For assets (images/css), prefer cache for speed, but fallback to network
  event.respondWith(
    caches.match(event.request).then((response) => {
      return response || fetch(event.request);
    })
  );
});

