  useEffect(() => {
    setAccounts(storageService.getAccounts());

    // --- URL CLEANING LOGIC ---
    // Remove query params and 'index.html' to get the clean directory URL
    try {
        const urlObj = new URL(window.location.href);
        // Strip search params to avoid ?mode=pwa causing loops
        urlObj.search = ''; 
        urlObj.hash = '';
        // If path ends in /index.html, strip it to just /
        let cleanPath = urlObj.href.replace(/\/index\.html$/, '/');
        // Ensure it ends with / if it doesn't have an extension
        if (!cleanPath.endsWith('/') && !cleanPath.includes('.')) {
            cleanPath += '/';
        }
        // Add a random timestamp to FORCE the browser to see it as a new page
        // But only for the display/copy, not for the window state
        setCurrentUrl(cleanPath);
    } catch (e) {
        setCurrentUrl(window.location.href);
    }

    // Check Platform
    const userAgent = window.navigator.userAgent.toLowerCase();
    setIsIOS(/iphone|ipad|ipod/.test(userAgent));

    // 1. Capture the Android install prompt
    const handleInstallPrompt = (e: any) => { 
        e.preventDefault(); 
        setInstallPrompt(e); 
