                            <div className="flex items-start gap-4">
                                <div className="w-8 h-8 rounded-lg bg-zinc-700 flex items-center justify-center flex-shrink-0 text-blue-400 font-bold">2</div>
                                <div>
                                    <p className="text-white text-sm font-bold">إضافة إلى الصفحة الرئيسية</p>
                                    <p className="text-zinc-500 text-xs mt-1">Add to Home Screen</p>
                                    <div className="flex items-center gap-2 mt-2 bg-zinc-700/50 px-3 py-1.5 rounded-lg w-fit">
                                        <PlusSquare className="w-4 h-4" />
                                        <span className="text-xs">إضافة</span>
                                    </div>
                                </div>
                            </div>
                        </>
                    ) : (
                    /* Android Instructions */
                        <>
                             <div className="flex items-start gap-4">
                                <div className="w-8 h-8 rounded-lg bg-zinc-700 flex items-center justify-center flex-shrink-0 text-blue-400 font-bold">1</div>
                                <div>
                                    <p className="text-white text-sm font-bold">اضغط على القائمة (ثلاث نقاط)</p>
                                    <p className="text-zinc-500 text-xs mt-1">موجودة في الزاوية العلوية للمتصفح</p>
                                    <MoreVertical className="w-5 h-5 text-zinc-400 mt-2" />
                                </div>
                            </div>
                            <div className="w-full h-[1px] bg-zinc-700/50" />
                            <div className="flex items-start gap-4">
                                <div className="w-8 h-8 rounded-lg bg-zinc-700 flex items-center justify-center flex-shrink-0 text-blue-400 font-bold">2</div>
                                <div>
                                    <p className="text-white text-sm font-bold">تثبيت التطبيق</p>
                                    <p className="text-zinc-500 text-xs mt-1">Install App</p>
                                    <div className="flex items-center gap-2 mt-2 bg-zinc-700/50 px-3 py-1.5 rounded-lg w-fit">
                                        <Smartphone className="w-4 h-4" />
                                        <span className="text-xs">تثبيت</span>
                                    </div>
                                </div>
                            </div>
                        </>
                    )}
                 </div>

                 <button onClick={() => setShowInstallHelp(false)} className="w-full bg-zinc-100 hover:bg-white text-black font-bold py-4 rounded-2xl mt-8">
                    فهمت، شكراً
                 </button>
              </div>
           </div>
        </div>
      )}

      {accountToDelete && (
        <div className="fixed inset-0 z-[70] flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={() => setAccountToDelete(null)} />
            <div className="bg-zinc-900 border border-zinc-700 w-full max-w-sm rounded-3xl p-6 relative z-10 shadow-2xl animate-shake">
                <div className="w-16 h-16 bg-red-500/10 rounded-full flex items-center justify-center mx-auto mb-4 border border-red-500/20"><AlertTriangle className="w-8 h-8 text-red-500" /></div>
                <h3 className="text-xl font-bold text-white text-center mb-2">حذف الحساب؟</h3>
                <p className="text-zinc-400 text-center text-sm mb-8">هل أنت متأكد؟ لا يمكن التراجع.</p>
                <div className="flex gap-3">
                    <button onClick={() => setAccountToDelete(null)} className="flex-1 py-3.5 rounded-2xl bg-zinc-800 text-white font-bold hover:bg-zinc-700 transition-colors">إلغاء</button>
                    <button onClick={confirmDelete} className="flex-1 py-3.5 rounded-2xl bg-red-600 text-white font-bold hover:bg-red-700 transition-colors shadow-lg">حذف</button>
                </div>
            </div>
        </div>
      )}

      {isModalOpen && (
        <div className="fixed inset-0 z-[60] flex items-end sm:items-center justify-center">
            <div className="absolute inset-0 bg-black/90 backdrop-blur-md" onClick={() => setIsModalOpen(false)} />
            <div className="glass-panel w-full sm:w-[400px] rounded-t-[2.5rem] sm:rounded-[2.5rem] p-8 relative z-10 animate-shake transform transition-transform duration-300 translate-y-0 border-t border-white/10">
                <div className="w-16 h-1.5 bg-zinc-700/50 rounded-full mx-auto mb-8" />
                <h2 className="text-2xl font-bold mb-8 text-center text-white">إضافة حساب</h2>
                <form onSubmit={handleAddAccount} className="space-y-5">
                    <div>
                        <label className="text-xs font-bold text-zinc-400 block mb-2 mr-1">المنصة</label>
                        <input required className="w-full bg-zinc-800/50 border border-zinc-700/50 rounded-2xl p-4 text-white focus:border-primary focus:outline-none" value={newTitle} onChange={(e) => setNewTitle(e.target.value)} placeholder="مثال: سناب شات" />
                    </div>
                    <div>
                        <label className="text-xs font-bold text-zinc-400 block mb-2 mr-1">المستخدم</label>
                        <input className="w-full bg-zinc-800/50 border border-zinc-700/50 rounded-2xl p-4 text-white focus:border-primary focus:outline-none dir-ltr text-right" value={newUsername} onChange={(e) => setNewUsername(e.target.value)} />
                    </div>
                    <div>
                        <label className="text-xs font-bold text-zinc-400 block mb-2 mr-1">كلمة المرور</label>
                        <input required type="text" className="w-full bg-zinc-800/50 border border-zinc-700/50 rounded-2xl p-4 text-white focus:border-primary focus:outline-none font-mono text-center tracking-widest text-lg" value={newPassword} onChange={(e) => setNewPassword(e.target.value)} />
                        <div className="flex gap-1 mt-2 h-1 px-1">
                            <div className={`flex-1 rounded-full transition-colors ${strength > 0 ? (strength < 3 ? 'bg-red-500' : strength < 5 ? 'bg-yellow-500' : 'bg-green-500') : 'bg-zinc-800'}`}></div>
                            <div className={`flex-1 rounded-full transition-colors ${strength > 2 ? (strength < 5 ? 'bg-yellow-500' : 'bg-green-500') : 'bg-zinc-800'}`}></div>
                            <div className={`flex-1 rounded-full transition-colors ${strength > 4 ? 'bg-green-500' : 'bg-zinc-800'}`}></div>
                        </div>
                    </div>
                    <div className="grid grid-cols-4 gap-3">
                        {(['social', 'banking', 'work', 'other'] as const).map(cat => (
                            <button key={cat} type="button" onClick={() => setNewCategory(cat)} className={`py-3 rounded-xl text-xs font-bold border transition-all ${newCategory === cat ? 'bg-primary border-primary text-white scale-105' : 'bg-zinc-800/50 border-zinc-700/50 text-zinc-400'}`}>
                                {cat === 'social' ? 'تواصل' : cat === 'banking' ? 'بنكي' : cat === 'work' ? 'عمل' : 'عام'}
                            </button>
                        ))}
                    </div>
                    <button type="submit" className="w-full bg-primary hover:bg-blue-600 text-white font-bold text-lg py-4 rounded-2xl mt-6 transition-all shadow-lg active:scale-95">حفظ</button>
                </form>
            </div>
        </div>
      )}
    </div>
  );
};

export default Vault;

import React, { useState, useEffect } from 'react';
import { Plus, Search, Copy, Eye, EyeOff, Wallet, Globe, Briefcase, Lock, CreditCard, Download, Check, Trash2, ArrowUpDown, Filter, AlertTriangle, Share, PlusSquare, X, Smartphone, MoreVertical, ExternalLink, Link as LinkIcon } from 'lucide-react';
import { Account } from '../types';
import * as storageService from '../services/storageService';

const Vault: React.FC = () => {
  const [accounts, setAccounts] = useState<Account[]>([]);
  const [search, setSearch] = useState('');
  const [sortOption, setSortOption] = useState<'newest' | 'oldest' | 'az' | 'za'>('newest');
  const [selectedCategory, setSelectedCategory] = useState<string>('all');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSortMenuOpen, setIsSortMenuOpen] = useState(false);
  const [revealedIds, setRevealedIds] = useState<Set<string>>(new Set());
  const [copiedId, setCopiedId] = useState<string | null>(null);

  // Installation & Link State
  const [installPrompt, setInstallPrompt] = useState<any>(null);
  const [showInstallHelp, setShowInstallHelp] = useState(false);
  const [isStandalone, setIsStandalone] = useState(false);
  const [isIOS, setIsIOS] = useState(false);
  const [showLinkModal, setShowLinkModal] = useState(false);
  const [currentUrl, setCurrentUrl] = useState('');

  const [accountToDelete, setAccountToDelete] = useState<string | null>(null);

  // New Account Form
  const [newTitle, setNewTitle] = useState('');
  const [newUsername, setNewUsername] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [newCategory, setNewCategory] = useState<Account['category']>('other');

  useEffect(() => {
    setAccounts(storageService.getAccounts());

    // --- SIMPLIFIED URL LOGIC ---
    // Just get the base URL without the garbage long query parameters
    try {
        const cleanPath = window.location.origin + window.location.pathname;
        setCurrentUrl(cleanPath);
    } catch (e) {
        setCurrentUrl(window.location.href);
    }

    // Check Platform
    const userAgent = window.navigator.userAgent.toLowerCase();
    setIsIOS(/iphone|ipad|ipod/.test(userAgent));

    // 1. Capture the Android install prompt
    const handleInstallPrompt = (e: any) => { 
        e.preventDefault(); 
        setInstallPrompt(e); 
        console.log("Install prompt captured");
    };
    window.addEventListener('beforeinstallprompt', handleInstallPrompt);

    // 2. Check if already installed (Standalone mode)
    const checkStandalone = () => {
        const isStandaloneMode = window.matchMedia('(display-mode: standalone)').matches || (window.navigator as any).standalone;
        setIsStandalone(!!isStandaloneMode);
    };
    checkStandalone();
    window.matchMedia('(display-mode: standalone)').addEventListener('change', checkStandalone);

    return () => {
        window.removeEventListener('beforeinstallprompt', handleInstallPrompt);
    };
  }, []);

  const handleInstallClick = async () => {
    if (installPrompt) {
        // Android / Chrome Desktop: Trigger native prompt
        installPrompt.prompt();
        const { outcome } = await installPrompt.userChoice;
        if (outcome === 'accepted') setInstallPrompt(null);
    } else {
        // Fallback: Show manual instructions
        setShowInstallHelp(true);
    }
  };

  const handleShareApp = () => {
    // Refresh clean URL
    const cleanPath = window.location.origin + window.location.pathname;
    setCurrentUrl(cleanPath);
    setShowLinkModal(true);
  };

  const copyUrl = () => {
    try {
      navigator.clipboard.writeText(currentUrl);
      alert('تم نسخ الرابط المختصر.');
    } catch (e) {
      alert('لم نتمكن من النسخ تلقائياً.');
    }
  };

  const getFilteredAndSortedAccounts = () => {
    let filtered = accounts;
    if (search) {
      filtered = filtered.filter(acc => 
        acc.title.toLowerCase().includes(search.toLowerCase()) || 
        acc.username.toLowerCase().includes(search.toLowerCase())
      );
    }
    if (selectedCategory !== 'all') {
      filtered = filtered.filter(acc => acc.category === selectedCategory);
    }
    return filtered.sort((a, b) => {
      switch (sortOption) {
        case 'newest': return b.createdAt - a.createdAt;
        case 'oldest': return a.createdAt - b.createdAt;
        case 'az': return a.title.localeCompare(b.title);
        case 'za': return b.title.localeCompare(a.title);
        default: return 0;
      }
    });
  };

  const displayedAccounts = getFilteredAndSortedAccounts();

  const toggleReveal = (e: any, id: string) => {
    e.stopPropagation();
    if(navigator.vibrate) navigator.vibrate(10);
    setRevealedIds(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };

  const copyToClipboard = (e: any, text: string, id: string) => {
    e.stopPropagation();
    if(navigator.vibrate) navigator.vibrate(10);
    navigator.clipboard.writeText(text);
    setCopiedId(id);
    setTimeout(() => setCopiedId(null), 2000);
  };

  const requestDelete = (e: any, id: string) => {
    e.stopPropagation(); 
    e.nativeEvent.stopImmediatePropagation();
    if(navigator.vibrate) navigator.vibrate(20);
    setAccountToDelete(id);
  };

  const confirmDelete = () => {
    if (accountToDelete) {
        if(navigator.vibrate) navigator.vibrate([30, 50]);
        const updated = storageService.deleteAccount(accountToDelete);
        setAccounts(updated);
        setAccountToDelete(null);
    }
  };

  const handleAddAccount = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTitle || !newPassword) return;
    const newAccount: Account = {
      id: Date.now().toString(),
      title: newTitle,
      username: newUsername,
      password: newPassword,
      category: newCategory,
      color: getRandomColor(),
      createdAt: Date.now(),
    };
    const updated = storageService.saveAccount(newAccount);
    setAccounts(updated);
    setNewTitle(''); setNewUsername(''); setNewPassword(''); setIsModalOpen(false);
  };

  const getRandomColor = () => {
    const colors = ['from-blue-600 to-blue-800', 'from-purple-600 to-purple-800', 'from-emerald-600 to-emerald-800', 'from-rose-600 to-rose-800', 'from-orange-600 to-orange-800', 'from-slate-700 to-slate-900'];
    return colors[Math.floor(Math.random() * colors.length)];
  };

  const getIcon = (category: string) => {
    switch(category) {
        case 'banking': return <Wallet className="w-5 h-5" />;
        case 'social': return <Globe className="w-5 h-5" />;
        case 'work': return <Briefcase className="w-5 h-5" />;
        default: return <Lock className="w-5 h-5" />;
    }
  };

  const getPasswordStrength = (pass: string) => {
      if(pass.length === 0) return 0;
      let score = 0;
      if(pass.length > 8) score++;
      if(pass.length > 12) score++;
      if(/[A-Z]/.test(pass)) score++;
      if(/[0-9]/.test(pass)) score++;
      if(/[^A-Za-z0-9]/.test(pass)) score++;
      return score;
  };
  const strength = getPasswordStrength(newPassword);

  const categories = [
    { id: 'all', label: 'الكل' },
    { id: 'banking', label: 'بنكي' },
    { id: 'social', label: 'تواصل' },
    { id: 'work', label: 'عمل' },
    { id: 'other', label: 'عام' },
  ];

  return (
    <div className="w-full h-full pb-32 px-4 pt-4 overflow-y-auto no-scrollbar font-sans" onClick={() => setIsSortMenuOpen(false)}>
      <div className="flex justify-between items-center mb-6 mt-4">
        <div>
            <h1 className="text-3xl font-extrabold text-white tracking-tight">الخزنة</h1>
            <p className="text-zinc-400 text-sm mt-1 font-medium">{displayedAccounts.length} حسابات</p>
        </div>
        <div className="flex gap-2">
            <button onClick={handleShareApp} className="w-12 h-12 rounded-full bg-zinc-800 border border-zinc-700 hover:border-blue-400/50 flex items-center justify-center text-zinc-400 hover:text-white transition-all active:scale-95 group relative overflow-hidden">
                <Share className="w-5 h-5" />
                <div className="absolute inset-0 bg-white/5 opacity-0 group-hover:opacity-100 transition-opacity" />
            </button>

            {!isStandalone && (
                <button onClick={handleInstallClick} className="h-12 px-5 rounded-full bg-primary border border-blue-400 flex items-center justify-center text-white hover:bg-blue-600 transition-colors shadow-[0_0_15px_rgba(10,132,255,0.4)] active:scale-95 gap-2 animate-pulse">
                <Download className="w-5 h-5" /><span className="text-sm font-bold hidden sm:inline">تثبيت</span>
                </button>
            )}
            <button onClick={() => setIsModalOpen(true)} className="w-12 h-12 rounded-full bg-zinc-800 border border-zinc-700 flex items-center justify-center text-primary hover:bg-zinc-700 transition-colors shadow-lg active:scale-95">
            <Plus className="w-6 h-6" />
            </button>
        </div>
      </div>

      {/* ... Search and Filters ... */}
      <div className="flex gap-2 mb-4">
        <div className="relative flex-1">
            <Search className="absolute right-4 top-1/2 transform -translate-y-1/2 w-5 h-5 text-zinc-500" />
            <input type="text" placeholder="بحث..." value={search} onChange={(e) => setSearch(e.target.value)} className="w-full bg-zinc-900/80 border border-zinc-800 rounded-2xl py-4 pr-12 pl-4 text-white placeholder-zinc-600 focus:outline-none focus:border-primary/50 focus:ring-1 focus:ring-primary/50 transition-all shadow-inner backdrop-blur-sm" />
        </div>
        <div className="relative">
            <button onClick={(e) => { e.stopPropagation(); setIsSortMenuOpen(!isSortMenuOpen); }} className="h-full px-4 rounded-2xl bg-zinc-900/80 border border-zinc-800 flex items-center justify-center text-zinc-400 hover:text-white transition-colors">
                <ArrowUpDown className="w-5 h-5" />
            </button>
            {isSortMenuOpen && (
                <div className="absolute left-0 mt-2 w-48 bg-zinc-900 border border-zinc-700 rounded-xl shadow-2xl z-50 overflow-hidden">
                    <button onClick={() => setSortOption('newest')} className={`w-full text-right px-4 py-3 text-sm hover:bg-zinc-800 ${sortOption === 'newest' ? 'text-primary' : 'text-white'}`}>الأحدث إضافة</button>
                    <button onClick={() => setSortOption('oldest')} className={`w-full text-right px-4 py-3 text-sm hover:bg-zinc-800 ${sortOption === 'oldest' ? 'text-primary' : 'text-white'}`}>الأقدم إضافة</button>
                    <button onClick={() => setSortOption('az')} className={`w-full text-right px-4 py-3 text-sm hover:bg-zinc-800 ${sortOption === 'az' ? 'text-primary' : 'text-white'}`}>الاسم (أ-ي)</button>
                    <button onClick={() => setSortOption('za')} className={`w-full text-right px-4 py-3 text-sm hover:bg-zinc-800 ${sortOption === 'za' ? 'text-primary' : 'text-white'}`}>الاسم (ي-أ)</button>
                </div>
            )}
        </div>
      </div>

      <div className="flex gap-2 mb-8 overflow-x-auto no-scrollbar pb-1">
        {categories.map((cat) => (
            <button key={cat.id} onClick={() => setSelectedCategory(cat.id)} className={`px-5 py-2.5 rounded-full text-sm font-bold whitespace-nowrap transition-all duration-300 ${selectedCategory === cat.id ? 'bg-white text-black shadow-lg scale-105' : 'bg-zinc-800/50 text-zinc-400 border border-zinc-700/30 hover:bg-zinc-700'}`}>
                {cat.label}
            </button>
        ))}
      </div>

      <div className="space-y-4">
        {displayedAccounts.length === 0 ? (
            <div className="text-center py-16 opacity-50 flex flex-col items-center animate-fade-in-up">
                <div className="w-20 h-20 bg-zinc-900 rounded-full flex items-center justify-center mb-4 border border-zinc-800">
                   <Lock className="w-10 h-10 text-zinc-700" />
                </div>
                <h3 className="text-lg font-bold text-zinc-300">لا توجد حسابات</h3>
            </div>
        ) : (
            displayedAccounts.map((account) => (
            <div key={account.id} className="relative group perspective animate-fade-in-up">
                <div className={`relative p-6 rounded-3xl bg-gradient-to-br ${account.color} border border-white/10 shadow-xl overflow-hidden transform transition-transform active:scale-[0.99] touch-pan-x`}>

                    <button 
                         onClick={(e) => requestDelete(e, account.id)}
                         className="absolute top-4 left-4 w-10 h-10 bg-black/20 hover:bg-red-500/80 rounded-full flex items-center justify-center text-white/70 hover:text-white transition-all backdrop-blur-sm z-50 active:scale-90"
                         style={{ pointerEvents: 'auto' }} 
                    >
                        <Trash2 className="w-4 h-4" />
                    </button>

                    <div className="flex justify-between items-start mb-8 pl-12"> 
                        <div className="flex items-center gap-2">
                             <div className="w-10 h-7 rounded-md bg-gradient-to-br from-yellow-200/40 to-yellow-400/30 border border-yellow-200/30 flex items-center justify-center backdrop-blur-sm shadow-sm">
                                <div className="w-full h-[1px] bg-black/10 absolute top-2"></div>
                                <div className="w-full h-[1px] bg-black/10 absolute bottom-2"></div>
                             </div>
                        </div>
                        <div className="p-2 bg-black/20 backdrop-blur-md rounded-xl border border-white/5">{getIcon(account.category)}</div>
                    </div>
                    <div className="mb-6">
                        <h3 className="text-2xl font-bold text-white mb-1 tracking-wide drop-shadow-md">{account.title}</h3>
                        <p className="text-white/80 text-sm font-medium">{account.username}</p>
                    </div>
                    <div className="flex items-center justify-between gap-3 relative z-20">
                        <div className="flex-1 bg-black/30 rounded-xl p-3 backdrop-blur-md border border-white/5 flex items-center h-12">
                            <span className={`font-mono text-white text-lg tracking-widest truncate dir-ltr text-left w-full transition-all duration-300 ${revealedIds.has(account.id) ? 'blur-none' : 'blur-[4px] select-none'}`}>{account.password}</span>
                        </div>
                        <button onClick={(e) => toggleReveal(e, account.id)} className="w-12 h-12 flex-shrink-0 flex items-center justify-center bg-black/20 hover:bg-white/10 rounded-xl transition-colors backdrop-blur-sm border border-white/5 active:scale-90 touch-manipulation">
                            {revealedIds.has(account.id) ? <EyeOff className="w-5 h-5" /> : <Eye className="w-5 h-5" />}
                        </button>
                        <button onClick={(e) => copyToClipboard(e, account.password, account.id)} className={`w-12 h-12 flex-shrink-0 flex items-center justify-center rounded-xl transition-all backdrop-blur-sm border border-white/5 active:scale-90 touch-manipulation ${copiedId === account.id ? 'bg-green-500/20 text-green-400 border-green-500/30' : 'bg-black/20 hover:bg-white/10'}`}>
                            {copiedId === account.id ? <Check className="w-5 h-5" /> : <Copy className="w-5 h-5" />}
                        </button>
                    </div>
                </div>
            </div>
            ))
        )}
      </div>

      {/* --- LINK DISPLAY MODAL --- */}
      {showLinkModal && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-black/90 backdrop-blur-md" onClick={() => setShowLinkModal(false)} />
            <div className="bg-zinc-900 border border-zinc-700 w-full max-w-sm rounded-3xl p-6 relative z-10 shadow-2xl animate-fade-in-up">
                <button onClick={() => setShowLinkModal(false)} className="absolute top-4 left-4 text-zinc-500 hover:text-white">
                    <X className="w-6 h-6" />
                </button>
                <div className="w-16 h-16 bg-blue-500/10 rounded-full flex items-center justify-center mx-auto mb-4 border border-blue-500/20">
                    <LinkIcon className="w-8 h-8 text-blue-500" />
                </div>
                <h3 className="text-xl font-bold text-white text-center mb-2">رابط التطبيق المختصر</h3>
                <p className="text-zinc-400 text-center text-sm mb-6">هذا الرابط الجديد (نظيف وقصير) ويعمل بشكل أفضل:</p>

                {/* Clean URL */}
                <a 
                   href={currentUrl}
                   target="_blank" 
                   rel="noopener noreferrer"
                   className="w-full py-4 rounded-2xl bg-primary text-white font-bold hover:bg-blue-600 transition-colors shadow-[0_0_20px_rgba(10,132,255,0.3)] flex items-center justify-center gap-2 mb-4 animate-pulse"
                >
                    <ExternalLink className="w-5 h-5" />
                    <span>فتح في المتصفح</span>
                </a>

                <div className="bg-zinc-950 p-3 rounded-xl border border-zinc-800 mb-4 relative group">
                    <p className="text-zinc-500 font-mono text-xs break-all text-left dir-ltr truncate">{currentUrl}</p>
                </div>

