const CACHE_NAME = 'my-guardian-v18-reset';
const APP_SHELL = './index.html';

const ASSETS = [
  './',
  './index.html',
  './manifest.json',
  './index.tsx',
  'https://cdn.tailwindcss.com',
  'https://fonts.googleapis.com/css2?family=Tajawal:wght@300;400;500;700;800&display=swap'
];

self.addEventListener('install', (event) => {
  self.skipWaiting();
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => {
      // Force reload from network for the app shell to fix encoding issues
      cache.add(new Request(APP_SHELL, { cache: 'reload' }));
      return cache.addAll(ASSETS.map(url => new Request(url, { cache: 'reload' }))).catch(e => console.log(e));
    })
  );
});

self.addEventListener('activate', (event) => {
  event.waitUntil(
    Promise.all([
      self.clients.claim(),
      caches.keys().then((keys) => {
        return Promise.all(
          keys.map((key) => {
            if (key !== CACHE_NAME) {
              return caches.delete(key);
            }
          })
        );
      })
    ])
  );
});

self.addEventListener('fetch', (event) => {
  if (event.request.mode === 'navigate') {
    event.respondWith(
      fetch(event.request)
        .catch(() => {
            return caches.match(APP_SHELL).then(response => {
                return response || caches.match('./index.html');
            });
        })
    );
    return;
  }
  event.respondWith(
    caches.match(event.request).then((response) => {
      return response || fetch(event.request);
    })
  );
});

const CACHE_NAME = 'my-guardian-v20-network-only';

// INSTALL: Force immediate takeover
self.addEventListener('install', (event) => {
  self.skipWaiting();
});

// ACTIVATE: Delete ALL previous caches
self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches.keys().then((keyList) => {
      return Promise.all(keyList.map((key) => {
        console.log('[SW] Removing old cache', key);
        return caches.delete(key);
      }));
    }).then(() => self.clients.claim())
  );
});

// FETCH: Network Only (Bypass Cache to fix encoding/stale issues)
self.addEventListener('fetch', (event) => {
  // Always go to network
  event.respondWith(fetch(event.request));
});

