const getRandom = (arr: string[]) => arr[Math.floor(Math.random() * arr.length)];
const GLOBAL_HISTORY = new Set<string>();

const getContentNoRepeat = (type: 'jokes' | 'facts' | 'stories' | 'security_tips') => {
  const source = DB[type];
  const available = source.filter(item => !GLOBAL_HISTORY.has(item));
  if (available.length === 0) {
    source.forEach(item => GLOBAL_HISTORY.delete(item));
    return getRandom(source);
  }
  const selected = getRandom(available);
  GLOBAL_HISTORY.add(selected);
  return selected;
};

const processOfflineInput = (text: string, imageProvided?: boolean): string => {
  if (imageProvided) {
      return "عذراً يا غالي 😓، ما أقدر أشوف الصور وأنا في الوضع المحلي (بدون نت). شغل النت عشان أحلل الصورة.";
  }

  const cleanText = normalizeArabic(text.toLowerCase());
  let response = "";

  if (cleanText.match(/كلمه سر|باسورد|رمز|password/)) {
     const pass = Array.from(crypto.getRandomValues(new Uint32Array(16)))
        .map(x => "ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnpqrstuvwxyz23456789!@#$%&"[x % 64])
        .join('');
     return `سم، هذي كلمة سر قوية جداً من أجلك: 👇\n\n[[PASSWORD:${pass}]]`;
  }

  if (cleanText.match(/كمان|بعد|غيرها|ثانيه|زياده/) && MEMORY.lastTopic) {
      switch (MEMORY.lastTopic) {
          case 'joke': return getRandom(DB.patterns.find(p => p.intent === 'more')?.responses || []) + "\n\n" + getContentNoRepeat('jokes');
          case 'fact': return getRandom(DB.patterns.find(p => p.intent === 'more')?.responses || []) + "\n\n" + getContentNoRepeat('facts');
          case 'story': return getRandom(DB.patterns.find(p => p.intent === 'more')?.responses || []) + "\n\n" + getContentNoRepeat('stories');
          case 'security': return getRandom(DB.patterns.find(p => p.intent === 'more')?.responses || []) + "\n\n" + getContentNoRepeat('security_tips');
      }
  }

  let matchedPattern = null;
  for (const p of DB.patterns) {
      if (p.regex.test(cleanText)) {
          matchedPattern = p;
          break;
      }
  }

  if (matchedPattern) {
      const prefix = getRandom(matchedPattern.responses);
      switch (matchedPattern.intent) {
          case 'joke': MEMORY.lastTopic = 'joke'; response = `${prefix}\n\n${getContentNoRepeat('jokes')}`; break;
          case 'story': MEMORY.lastTopic = 'story'; response = `${prefix}\n\n${getContentNoRepeat('stories')}`; break;
          case 'fact': MEMORY.lastTopic = 'fact'; response = `${prefix}\n\n${getContentNoRepeat('facts')}`; break;
          case 'security': MEMORY.lastTopic = 'security'; response = `${prefix}\n\n${getContentNoRepeat('security_tips')}`; break;
          case 'install': response = prefix; break;
          case 'greeting': 
              const hour = new Date().getHours();
              const timeGreeting = hour < 12 ? "صباح الخير" : "مساء النور";
              response = `${prefix} ${timeGreeting} ${MEMORY.userNickname}!`;
              break;
          default: MEMORY.lastTopic = 'general'; response = prefix;
      }
  } else {
      MEMORY.lastTopic = 'general';
      if (cleanText.length < 2) response = "كمل، أنا أسمعك..";
      else if (cleanText.includes("؟")) response = "سؤال جميل.. بس بصراحة وأنا في الوضع المحلي (Offline) معلوماتي محدودة، بس في السوالف والأمان أنا موجود!";
      else if (cleanText.includes("وين")) response = "موجود بجوالك، أقرب لك من أنفاسك.";
      else {
          const reflections = ["حلو.. وش كمان؟", "تصدق نقطة مثيرة للاهتمام.", `فعلاً يا ${MEMORY.userNickname}، كلامك صحيح.`, "أنا أتفق معك.", "ياخي تعجبني سواليفك."];
          response = getRandom(reflections);
      }
  }
  return response;
};

// --- PUBLIC API ---

export const generateSecurityAdvice = async (message: string, imageBase64?: string): Promise<string> => {
  // Offline Check
  if (!navigator.onLine) {
    return processOfflineInput(message, !!imageBase64);
  }

  try {
    const ai = getClient();
    if (!ai) return processOfflineInput(message, !!imageBase64);

    // Model Selection: Banana (gemini-2.5-flash-image) if image present, else Flash
    const model = imageBase64 ? "gemini-2.5-flash-image" : "gemini-2.5-flash";

    const systemInstruction = `أنت تطبيق ويب تقدمي (PWA) واسمك "حارسي الأمين".
    - وظيفتك: حماية كلمات المرور، الدردشة الممتعة، وتحليل الصور (Banana model).
    - اللهجة: سعودية بيضاء ودودة جداً.
    - إذا أرسل المستخدم صورة: حللها بدقة. إذا كانت صورة احتيال أو رسالة مشبوهة، حذره فوراً. إذا كانت صورة عادية، علق عليها بأسلوب لطيف.
    `;

    // Construct Request
    let contents: any;
    if (imageBase64) {
        // Multimodal Request (Text + Image)
        const cleanBase64 = imageBase64.split(',')[1] || imageBase64;
        contents = {
            parts: [
                { text: message || "وش رايك في هالصورة؟" }, // Default prompt if text empty
                { inlineData: { mimeType: 'image/jpeg', data: cleanBase64 } }
            ]
        };
    } else {
        // Text Only Request
        contents = message;
    }

    const response = await ai.models.generateContent({
      model: model,
      contents: contents,
      config: { systemInstruction: systemInstruction }
    });

    return response.text || "عذراً، ما قدرت أفهم الرسالة. حاول مرة ثانية.";
  } catch (error) {
    console.log("Network AI failed, switching to local brain", error);
    return processOfflineInput(message, !!imageBase64);
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, Sparkles, WifiOff, Key, Smile, Lightbulb, ShieldAlert, Image as ImageIcon, X } from 'lucide-react';
import { generateSecurityAdvice } from '../services/geminiService';
import { ChatMessage } from '../types';

interface ChatProps {
  messages: ChatMessage[];
  setMessages: React.Dispatch<React.SetStateAction<ChatMessage[]>>;
}

const SUGGESTIONS = [
  { label: '🔐 ولد كلمة سر', text: 'ابي كلمة سر قوية', icon: <Key className="w-3 h-3" /> },
  { label: '😂 نكتة', text: 'قول نكتة', icon: <Smile className="w-3 h-3" /> },
  { label: '💡 معلومة', text: 'عطني معلومة غريبة', icon: <Lightbulb className="w-3 h-3" /> },
  { label: '🛡️ نصيحة', text: 'عطني نصيحة أمنية', icon: <ShieldAlert className="w-3 h-3" /> },
];

const Chat: React.FC<ChatProps> = ({ messages, setMessages }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);

  const endRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Monitor online status
  useEffect(() => {
    const handleStatusChange = () => {
      setIsOnline(navigator.onLine);
    };
    window.addEventListener('online', handleStatusChange);
    window.addEventListener('offline', handleStatusChange);
    return () => {
      window.removeEventListener('online', handleStatusChange);
      window.removeEventListener('offline', handleStatusChange);
    };
  }, []);

  const scrollToBottom = () => {
    endRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, loading, selectedImage]); // Scroll when image selected too

  const handleImageSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
        const reader = new FileReader();
        reader.onloadend = () => {
            setSelectedImage(reader.result as string);
        };
        reader.readAsDataURL(file);
    }
  };

  const clearImage = () => {
      setSelectedImage(null);
      if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleSend = async (textOverride?: string) => {
    const textToSend = textOverride || input.trim();
    // Allow sending if there is text OR an image
    if ((!textToSend && !selectedImage) || loading) return;

    if (!textOverride) setInput('');
    const imageToSend = selectedImage; // Capture current image
    clearImage(); // Clear preview

    // Haptic feedback
    if (navigator.vibrate) navigator.vibrate(10);

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: textToSend,
      image: imageToSend || undefined,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setLoading(true);

    try {
      if (!isOnline) {
        await new Promise(resolve => setTimeout(resolve, 600)); 
      }

      // Pass the image (if any) to the service
      const responseText = await generateSecurityAdvice(textToSend, imageToSend || undefined);

      const aiMsg: ChatMessage = {
          id: (Date.now() + 1).toString(),
          role: 'model',
          text: responseText,
          timestamp: Date.now()
      };

      setMessages(prev => [...prev, aiMsg]);
    } catch (error) {
      console.error("Chat Error:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="flex flex-col h-full bg-black/20 relative animate-fade-in">
       {/* Header */}
       <div className="px-6 py-4 border-b border-white/5 bg-black/60 backdrop-blur-xl sticky top-0 z-20 flex items-center gap-3 justify-between shadow-lg">
          <div className="flex items-center gap-4">
            <div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all shadow-lg ${isOnline ? 'bg-gradient-to-tr from-blue-600 to-cyan-500 shadow-blue-500/20' : 'bg-zinc-800 border border-zinc-700'}`}>
                {isOnline ? <Sparkles className="w-6 h-6 text-white" /> : <Bot className="w-6 h-6 text-zinc-400" />}
            </div>
            <div>
                <h2 className="font-bold text-lg text-white tracking-wide">الرفيق الذكي</h2>
                <div className="flex items-center gap-1.5 mt-0.5">
                    <span className={`w-2 h-2 rounded-full ${isOnline ? 'bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.6)]' : 'bg-amber-500'}`}></span>
                    <p className="text-xs font-medium text-zinc-400">
                        {isOnline ? 'Banana (Multimodal)' : 'الوضع المحلي'}
                    </p>
                </div>
            </div>
          </div>

          {!isOnline && (
            <div className="bg-amber-500/10 border border-amber-500/20 rounded-full p-2">
              <WifiOff className="w-5 h-5 text-amber-500" />
            </div>
          )}
       </div>

       {/* Messages */}
       <div className="flex-1 overflow-y-auto p-4 space-y-6 pb-48 no-scrollbar touch-pan-y">
          {messages.map((msg) => (
            <div 
              key={msg.id} 
              className={`flex ${msg.role === 'user' ? 'justify-start' : 'justify-end'} animate-fade-in-up`}
            >
               <div className={`flex gap-3 max-w-[85%] sm:max-w-[70%] ${msg.role === 'user' ? 'flex-row' : 'flex-row-reverse'}`}>
                  {/* Avatar */}
                  <div className={`w-8 h-8 rounded-full flex-shrink-0 flex items-center justify-center mt-auto shadow-md ${msg.role === 'user' ? 'bg-zinc-800 border border-zinc-700' : (isOnline ? 'bg-gradient-to-br from-blue-500 to-cyan-600' : 'bg-zinc-700')}`}>
                    {msg.role === 'user' ? <User className="w-4 h-4 text-zinc-400" /> : <Bot className="w-4 h-4 text-white" />}
                  </div>

                  {/* Bubble Container */}
                  <div className="flex flex-col gap-2">
                      {/* Image Attachment */}
                      {msg.image && (
                          <div className={`rounded-xl overflow-hidden border border-white/10 shadow-lg max-w-[200px] ${msg.role === 'user' ? 'self-start' : 'self-end'}`}>
                              <img src={msg.image} alt="Attachment" className="w-full h-auto object-cover" />
                          </div>
                      )}

                      {/* Text Bubble */}
                      {msg.text && (
                        <div className={`p-4 rounded-[1.2rem] text-[15px] leading-relaxed shadow-lg whitespace-pre-wrap ${
                            msg.role === 'user' 
                            ? 'bg-zinc-800 text-white rounded-br-none border border-zinc-700/50' 
                            : (isOnline 
                                    ? 'bg-gradient-to-br from-[#0A84FF] to-[#0063CC] text-white rounded-bl-none shadow-blue-900/20' 
                                    : 'bg-zinc-700 text-zinc-100 rounded-bl-none border border-zinc-600')
                        }`}>
                            {msg.text}
                        </div>
                      )}
                  </div>
               </div>
            </div>
          ))}

          {loading && (
             <div className="flex justify-end animate-fade-in-up">
               <div className="flex flex-row-reverse gap-3 max-w-[85%]">
                  <div className="w-8 h-8 rounded-full bg-zinc-800/50 flex items-center justify-center mt-auto border border-zinc-700/30">
                     <Bot className="w-4 h-4 text-zinc-500" />
                  </div>
                  <div className="bg-zinc-800/50 border border-zinc-700/30 p-4 rounded-[1.2rem] rounded-bl-none backdrop-blur-sm">
                     <div className="flex gap-1.5 items-center h-full">
                        <span className="w-2 h-2 bg-zinc-400 rounded-full animate-[bounce_1s_infinite_0ms]"></span>
                        <span className="w-2 h-2 bg-zinc-400 rounded-full animate-[bounce_1s_infinite_200ms]"></span>
                        <span className="w-2 h-2 bg-zinc-400 rounded-full animate-[bounce_1s_infinite_400ms]"></span>
                     </div>
                  </div>
               </div>
             </div>
          )}
          <div ref={endRef} />
       </div>

       {/* Input Area & Quick Actions */}
       <div className="absolute bottom-28 left-0 w-full z-30 flex flex-col gap-2">

          {/* Image Preview (If selected) */}
          {selectedImage && (
              <div className="mx-4 mb-1 p-2 bg-zinc-900/90 border border-zinc-700 rounded-2xl flex items-center gap-3 w-fit animate-fade-in-up backdrop-blur-md">
                  <div className="relative w-16 h-16 rounded-xl overflow-hidden border border-zinc-600">
                      <img src={selectedImage} className="w-full h-full object-cover" alt="Preview" />
                  </div>
                  <div className="flex flex-col">
                      <span className="text-xs font-bold text-white">صورة مختارة</span>
                      <span className="text-[10px] text-zinc-400">جاهزة للتحليل</span>
                  </div>
                  <button onClick={clearImage} className="p-1.5 bg-zinc-800 rounded-full text-zinc-400 hover:text-red-400 mr-2">
                      <X className="w-4 h-4" />
                  </button>
              </div>
          )}

          {/* Quick Actions Chips */}
          <div className="px-4 overflow-x-auto no-scrollbar flex gap-2 pb-1">
             {SUGGESTIONS.map((chip, idx) => (
                <button
                   key={idx}
                   onClick={() => handleSend(chip.text)}
                   disabled={loading}
                   className="flex items-center gap-1.5 bg-zinc-800/80 hover:bg-zinc-700 border border-zinc-600/50 backdrop-blur-md px-3 py-2 rounded-xl text-xs font-bold text-zinc-200 whitespace-nowrap transition-all active:scale-95"
                >
                   {chip.icon}
                   <span>{chip.label}</span>
                </button>
