import { GoogleGenAI } from "@google/genai";

let aiClient: GoogleGenAI | null = null;

const getClient = () => {
  if (!aiClient && process.env.API_KEY) {
    aiClient = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }
  return aiClient;
};

// ==========================================
//  OFFLINE BRAIN (Fallback)
// ==========================================

const processOfflineInput = (text: string, imageProvided?: boolean): { text: string, image?: string } => {
  if (imageProvided) {
      return { text: "عذراً يا غالي 😓، ما أقدر أشوف أو أعدل الصور وأنا في الوضع المحلي (بدون نت). شغل النت عشان نلعب بالصور!" };
  }

  // Simple conversational fallback
  return { text: "أنا حالياً في وضع 'عدم الاتصال' 🔌. أقدر أسولف معك، بس قدراتي الخارقة (مثل الرسم والبحث) تحتاج نت. جرب تشبك واي فاي!" };
};

// --- PUBLIC API ---

export const generateAIResponse = async (message: string, imageBase64?: string): Promise<{ text: string, image?: string }> => {
  // Offline Check
  if (!navigator.onLine) {
    return processOfflineInput(message, !!imageBase64);
  }

  try {
    const ai = getClient();
    if (!ai) return processOfflineInput(message, !!imageBase64);

    // Always use the Image model (Banana) to support multimodal inputs AND image generation outputs
    const model = "gemini-2.5-flash-image";

    const systemInstruction = `
    أنت مساعد ذكي متطور جداً ومبدع، تتحدث اللغة العربية بطلاقة وبأسلوب طبيعي وودود (ليس روبوتياً).

    قدراتك:
    1. محادثة عامة: تسولف، تجاوب، تضحك، وتتفاعل مع أي موضوع يطرحه المستخدم.
    2. تحليل الصور: إذا أرسل المستخدم صورة، حللها بدقة وعلق عليها.
    3. توليد وتعديل الصور: أنت قادر على رسم صور جديدة أو تعديل الصور المرفقة إذا طلب المستخدم ذلك.

    القواعد:
    - لا تتقمص شخصية "حارس أمني" بعد الآن. أنت مساعد شخصي شامل.
    - كن مختصراً ومفيداً، إلا إذا طلب منك المستخدم التفصيل.
    - إذا طلب المستخدم رسم شيء، أو تعديل صورة، نفذ ذلك فوراً.
    `;

    // Construct Request
    let contents: any;
    if (imageBase64) {
        // Multimodal Request (Text + Image) -> Used for Analysis or Editing
        const cleanBase64 = imageBase64.split(',')[1] || imageBase64;
        contents = {
            parts: [
                { text: message || "وش رايك في هالصورة؟" }, 
                { inlineData: { mimeType: 'image/jpeg', data: cleanBase64 } }
            ]
        };
    } else {
        // Text Only Request -> Used for Chat or Image Generation (Text-to-Image)
        contents = message;
    }

    const response = await ai.models.generateContent({
      model: model,
      contents: contents,
      config: { 
          systemInstruction: systemInstruction,
          // No special safety settings needed, let the model be creative
      }
    });

    let responseText = "";
    let responseImage = undefined;

    // Parse Response (Might contain Text AND/OR Image)
    if (response.candidates && response.candidates[0].content && response.candidates[0].content.parts) {
        for (const part of response.candidates[0].content.parts) {
            if (part.text) {
                responseText += part.text;
            }
            if (part.inlineData) {
                // Determine MIME type (default to png if not specified, though usually it is)
                const mime = part.inlineData.mimeType || 'image/png';
                responseImage = `data:${mime};base64,${part.inlineData.data}`;
            }
        }
    }

    return { 
        text: responseText || "ما فهمت عليك، ممكن تعيد؟", 
        image: responseImage 
    };

  } catch (error) {
    console.log("AI Generation failed", error);
    return { text: "صار عندي خطأ فني بسيط، ممكن تحاول مرة ثانية؟" };
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, Sparkles, WifiOff, Image as ImageIcon, X, Palette, Wand2, MessageCircle, Smile } from 'lucide-react';
