const Chat: React.FC<ChatProps> = ({ messages, setMessages }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);

  const endRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Monitor online status
  useEffect(() => {
    const handleStatusChange = () => {
      setIsOnline(navigator.onLine);
    };
    window.addEventListener('online', handleStatusChange);
    window.addEventListener('offline', handleStatusChange);
    return () => {
      window.removeEventListener('online', handleStatusChange);
      window.removeEventListener('offline', handleStatusChange);
    };
  }, []);

  const scrollToBottom = () => {
    endRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, loading, selectedImage]); 

  const handleImageSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
        const reader = new FileReader();
        reader.onloadend = () => {
            setSelectedImage(reader.result as string);
        };
        reader.readAsDataURL(file);
    }
  };

  const clearImage = () => {
      setSelectedImage(null);
      if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleSend = async (textOverride?: string) => {
    const textToSend = textOverride || input.trim();
    // Allow sending if there is text OR an image
    if ((!textToSend && !selectedImage) || loading) return;

    if (!textOverride) setInput('');
    const imageToSend = selectedImage; // Capture current image
    clearImage(); // Clear preview

    // Haptic feedback
    if (navigator.vibrate) navigator.vibrate(10);

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: textToSend,
      image: imageToSend || undefined,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setLoading(true);

    try {
      if (!isOnline) {
        await new Promise(resolve => setTimeout(resolve, 600)); 
      }

      // Call the NEW General AI Service
      const response = await generateAIResponse(textToSend, imageToSend || undefined);

      const aiMsg: ChatMessage = {
          id: (Date.now() + 1).toString(),
          role: 'model',
          text: response.text,
          image: response.image, // Handle generated image
          timestamp: Date.now()
      };

      setMessages(prev => [...prev, aiMsg]);
    } catch (error) {
      console.error("Chat Error:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="flex flex-col h-full bg-black/20 relative animate-fade-in">
       {/* Header */}
       <div className="px-6 py-4 border-b border-white/5 bg-black/60 backdrop-blur-xl sticky top-0 z-20 flex items-center gap-3 justify-between shadow-lg">
          <div className="flex items-center gap-4">
            <div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all shadow-lg ${isOnline ? 'bg-gradient-to-tr from-purple-600 to-pink-500 shadow-purple-500/20' : 'bg-zinc-800 border border-zinc-700'}`}>
                {isOnline ? <Sparkles className="w-6 h-6 text-white" /> : <Bot className="w-6 h-6 text-zinc-400" />}
            </div>
            <div>
                <h2 className="font-bold text-lg text-white tracking-wide">الذكاء الاصطناعي</h2>
                <div className="flex items-center gap-1.5 mt-0.5">
                    <span className={`w-2 h-2 rounded-full ${isOnline ? 'bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.6)]' : 'bg-amber-500'}`}></span>
                    <p className="text-xs font-medium text-zinc-400">
                        {isOnline ? 'مبدع & متعدد المهام' : 'وضع غير متصل'}
                    </p>
                </div>
            </div>
          </div>

          {!isOnline && (
            <div className="bg-amber-500/10 border border-amber-500/20 rounded-full p-2">
              <WifiOff className="w-5 h-5 text-amber-500" />
            </div>
          )}
       </div>

       {/* Messages */}
       <div className="flex-1 overflow-y-auto p-4 space-y-6 pb-48 no-scrollbar touch-pan-y">
          {messages.map((msg) => (
            <div 
              key={msg.id} 
              className={`flex ${msg.role === 'user' ? 'justify-start' : 'justify-end'} animate-fade-in-up`}
            >
               <div className={`flex gap-3 max-w-[85%] sm:max-w-[75%] ${msg.role === 'user' ? 'flex-row' : 'flex-row-reverse'}`}>
                  {/* Avatar */}
                  <div className={`w-8 h-8 rounded-full flex-shrink-0 flex items-center justify-center mt-auto shadow-md ${msg.role === 'user' ? 'bg-zinc-800 border border-zinc-700' : (isOnline ? 'bg-gradient-to-br from-purple-500 to-pink-600' : 'bg-zinc-700')}`}>
                    {msg.role === 'user' ? <User className="w-4 h-4 text-zinc-400" /> : <Bot className="w-4 h-4 text-white" />}
                  </div>

                  {/* Bubble Container */}
                  <div className="flex flex-col gap-2">
                      {/* Image Attachment (User Upload OR AI Generation) */}
                      {msg.image && (
                          <div className={`rounded-2xl overflow-hidden border border-white/10 shadow-lg ${msg.role === 'user' ? 'self-start max-w-[200px]' : 'self-end w-full'}`}>
                              <img src={msg.image} alt="Attachment" className="w-full h-auto object-cover" />
                              {msg.role === 'model' && (
                                <div className="absolute bottom-2 right-2 bg-black/50 px-2 py-1 rounded text-[10px] text-white backdrop-blur-md">تم التوليد بواسطة AI</div>
                              )}
