          <div className="px-4">
            <div className="glass-panel rounded-[2rem] p-1.5 flex items-end gap-2 shadow-[0_8px_32px_rgba(0,0,0,0.5)] border border-white/10 backdrop-blur-2xl bg-zinc-900/80">

