                            <div className={`flex-1 rounded-full transition-colors ${strength > 2 ? (strength < 5 ? 'bg-yellow-500' : 'bg-green-500') : 'bg-zinc-800'}`}></div>
                            <div className={`flex-1 rounded-full transition-colors ${strength > 4 ? 'bg-green-500' : 'bg-zinc-800'}`}></div>
