  const [selectedCategory, setSelectedCategory] = useState<string>('all');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSortMenuOpen, setIsSortMenuOpen] = useState(false);
  const [revealedIds, setRevealedIds] = useState<Set<string>>(new Set());

  // Track copied status separately for password and username
  const [copiedId, setCopiedId] = useState<string | null>(null); // For Password
  const [copiedUserAccount, setCopiedUserAccount] = useState<string | null>(null); // For Username

  const [installPrompt, setInstallPrompt] = useState<any>(null);
  const [showInstallHelp, setShowInstallHelp] = useState(false);
  const [isStandalone, setIsStandalone] = useState(false);
  const [isIOS, setIsIOS] = useState(false);
  const [showLinkModal, setShowLinkModal] = useState(false);
  const [currentUrl, setCurrentUrl] = useState('');
  const [isSecure, setIsSecure] = useState(true);

  const [accountToDelete, setAccountToDelete] = useState<string | null>(null);

  const [newTitle, setNewTitle] = useState('');
  const [newUsername, setNewUsername] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [newCategory, setNewCategory] = useState<Account['category']>('other');

  useEffect(() => {
    setAccounts(storageService.getAccounts());

    setCurrentUrl(window.location.href);

    if (window.location.protocol === 'http:' && window.location.hostname !== 'localhost') {
        setIsSecure(false);
    } else {
        setIsSecure(true);
    }

    const userAgent = window.navigator.userAgent.toLowerCase();
    setIsIOS(/iphone|ipad|ipod/.test(userAgent));

    const handleInstallPrompt = (e: any) => { 
        e.preventDefault(); 
        setInstallPrompt(e); 
    };
    window.addEventListener('beforeinstallprompt', handleInstallPrompt);

    const checkStandalone = () => {
        const isStandaloneMode = window.matchMedia('(display-mode: standalone)').matches || (window.navigator as any).standalone;
        setIsStandalone(!!isStandaloneMode);
    };
    checkStandalone();
    window.matchMedia('(display-mode: standalone)').addEventListener('change', checkStandalone);

    return () => {
        window.removeEventListener('beforeinstallprompt', handleInstallPrompt);
    };
  }, []);

  const handleInstallClick = async () => {
    if (installPrompt) {
        installPrompt.prompt();
        const { outcome } = await installPrompt.userChoice;
        if (outcome === 'accepted') setInstallPrompt(null);
    } else {
        setShowInstallHelp(true);
    }
  };

  const handleShareApp = () => {
    setCurrentUrl(window.location.href);
    setShowLinkModal(true);
  };

  const copyUrl = () => {
    try {
      navigator.clipboard.writeText(currentUrl);
      alert('تم النسخ بنجاح');
    } catch (e) {
      alert('الرجاء النسخ يدوياً');
    }
  };

  const getFilteredAndSortedAccounts = () => {
    let filtered = accounts;
    if (search) {
      filtered = filtered.filter(acc => 
        acc.title.toLowerCase().includes(search.toLowerCase()) || 
        acc.username.toLowerCase().includes(search.toLowerCase())
      );
    }
    if (selectedCategory !== 'all') {
      filtered = filtered.filter(acc => acc.category === selectedCategory);
    }
    return filtered.sort((a, b) => {
      switch (sortOption) {
        case 'newest': return b.createdAt - a.createdAt;
        case 'oldest': return a.createdAt - b.createdAt;
        case 'az': return a.title.localeCompare(b.title);
        case 'za': return b.title.localeCompare(a.title);
        default: return 0;
      }
    });
  };

  const displayedAccounts = getFilteredAndSortedAccounts();

  const toggleReveal = (e: any, id: string) => {
    e.stopPropagation();
    if(navigator.vibrate) navigator.vibrate(10);
    setRevealedIds(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };

  const copyPassword = (e: any, text: string, id: string) => {
    e.stopPropagation();
    if(navigator.vibrate) navigator.vibrate(10);
    navigator.clipboard.writeText(text);
    setCopiedId(id);
    setTimeout(() => setCopiedId(null), 2000);
  };

